#include <bits/stdc++.h>
using namespace std;

const int N=1010;

int n,x,p,m,a[N],ans;
int s[N][N],mi[N];

int qpow(int a,int b){
    long long ans=1,base=a;
    while(b){
        if(b&1)
            ans=ans*base%p;
        base=base*base%p,b>>=1;
    }
    return ans;
}

int main(){
    scanf("%d%d%d%d",&n,&x,&p,&m);
    for(int i=0;i<=m;i++)
        scanf("%d",&a[i]);
    for(int i=0;i<=m;i++)
        mi[i]=1ll*qpow(x,i)*qpow(x+1,n-i)%p;
    s[0][0]=1;
    for(int i=1;i<=m;i++)
        for(int j=1;j<=m;j++)
            s[i][j]=(s[i-1][j-1]+1ll*s[i-1][j]*j)%p;
    for(int i=0;i<=m;i++){
        int sum=0;
        for(int j=0,pr=1;j<=i;pr=1ll*pr*(n-j)%p,j++)
            sum=(sum+1ll*s[i][j]*pr%p*mi[j])%p;
        ans=(ans+1ll*a[i]*sum)%p;
    }
    printf("%d",ans);
    return 0;
}
